# Query-layer proxy: enforce scope and emit audit event
from fastapi import FastAPI, Request, Depends, HTTPException

app = FastAPI()

def scope_for(role: str) -> str:
    return {
        "engineer":        '{env="prod", sensitivity!="restricted"}',
        "support":         '{service="support-agent"}',
        "security_audit":  '{}',                    # full scope
    }.get(role, None)

@app.post("/query")
async def query(req: Request, principal=Depends(authenticate)):
    selector = scope_for(principal["role"])
    if selector is None:
        raise HTTPException(403, "no log scope for role")
    body = await req.json()
    # Force the scope filter onto the user's query
    body["query"] = f'{selector} |= {body.get("query", "")}'
    audit_event(principal, scope=selector, query=body["query"])
    return await forward_to_backend(body)

# Simple anomalous-access heuristics over the audit trail
def flag_anomalies(events, baselines):
    flags = []
    for principal, evs in group_by_principal(events).items():
        base = baselines.get(principal, {})
        scopes = {e["scope"] for e in evs}
        if len(scopes) > base.get("typical_scopes", 1) * 3:
            flags.append((principal, "scope_fanout", len(scopes)))
        off_hours = [e for e in evs if is_off_hours(e["ts"])]
        if len(off_hours) > base.get("off_hours_p95", 0):
            flags.append((principal, "off_hours_access", len(off_hours)))
        big = [e for e in evs if e.get("rows_returned", 0) > 100_000]
        if big:
            flags.append((principal, "bulk_export", len(big)))
    return flags

# Enforce tenant isolation at the read path
def resolve_tenant(principal) -> str:
    # Tenant is derived from the authenticated identity, never from the request
    return principal["tenant_id"]

def read_logs(principal, selector: str):
    tenant = resolve_tenant(principal)
    # The tenant label is injected by the platform and cannot be overridden
    enforced = f'{{tenant_id="{tenant}"}} {selector}'
    if principal["role"] == "security_audit" and principal.get("cross_tenant"):
        enforced = selector                      # exceptional, always audited
        audit_event(principal, scope="ALL_TENANTS", query=selector)
    else:
        audit_event(principal, scope=tenant, query=enforced)
    return backend_query(enforced)
